/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} source
 * @param {number} target
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // Collect all unique edge weights to form the search space for threshold
    let uniqueWeights = new Set([0]); // Include 0 as a possible threshold
    for (const edge of edges) {
        uniqueWeights.add(edge[2]);
    }
    let sortedWeights = Array.from(uniqueWeights).sort((a, b) => a - b);

    // Check function: Can we reach target from source with at most k heavy edges 
    // given a specific threshold?
    const canReach = (threshold) => {
        // dist[i][j] = minimum number of heavy edges to reach node i using exactly j heavy edges (or fewer)
        // Since we only care about existence, a simple BFS/Dijkstra variant on state (node, heavy_count) works.

        // State: [node, heavy_count]
        // We want the minimum number of heavy edges, so Dijkstra/0-1 BFS might be suitable if edge weights were fixed.
        // Here, the "cost" is the number of heavy edges.

        // Initialize distances: dist[node][heavy_count] = true if reachable
        // Max heavy_count needed is k. So size is n x (k+1)
        const reachable = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // Queue for BFS: [node, heavy_count]
        const queue = [[source, 0]];
        reachable[source][0] = true;

        let head = 0;
        while (head < queue.length) {
            const [u, heavyCount] = queue[head++];

            if (u === target) return true;

            for (const edge of edges) {
                const [u1, v1, w] = edge;
                let v;
                let isHeavy;

                // Determine the neighbor v and whether the edge is heavy
                if (u1 === u) {
                    v = v1;
                } else if (v1 === u) {
                    v = u1;
                } else {
                    continue; // Edge doesn't involve u
                }

                isHeavy = w > threshold;

                const nextHeavyCount = heavyCount + (isHeavy ? 1 : 0);

                if (nextHeavyCount <= k) {
                    if (!reachable[v][nextHeavyCount]) {
                        reachable[v][nextHeavyCount] = true;
                        queue.push([v, nextHeavyCount]);
                    }
                }
            }
        }
        return false;
    };

    // Binary Search on the sorted weights array (or directly on the range of weights)
    // Since we are looking for the MINIMUM threshold, we can binary search on the sorted unique weights.

    let low = 0;
    let high = sortedWeights.length - 1;
    let minThreshold = -1;

    while (low <= high) {
        const midIndex = Math.floor((low + high) / 2);
        const currentThreshold = sortedWeights[midIndex];

        if (canReach(currentThreshold)) {
            // This threshold works, try for a smaller one
            minThreshold = currentThreshold;
            high = midIndex - 1;
        } else {
            // This threshold is too small, need a larger one
            low = midIndex + 1;
        }
    }

    return minThreshold;
}

